class Solution:
    def longestDecomposition(self, text: str) -> int:
        n = len(text)
        for k in range(n // 2, 0, -1):
            if n % k != 0:
                continue
            substrings = [text[i:i+k] for i in range(0, n, k)]
            if substrings == substrings[::-1]:
                return len(substrings)
        return 1
